// src/pages/PostInternship.jsx
import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

export default function PostInternship() {
  const { currentUser } = useAuth();
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    title: "",
    company: "",
    location: "",
    description: "",
    duration: "",
    stipend: "",
  });

  useEffect(() => {
    // Redirect if not Admin or HR
    if (!currentUser || !["Admin", "HR"].includes(currentUser.role)) {
      alert("Access denied: Only Admin or HR can post internships.");
      navigate("/internship");
    }
  }, [currentUser, navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/api/internships", {
        ...formData,
        postedBy: currentUser.name,
      });
      alert("✅ Internship posted successfully!");
      navigate("/internship");
    } catch (err) {
      console.error(err);
      alert("❌ Error posting internship");
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-6 bg-white shadow-md rounded-lg mt-6">
      <h2 className="text-3xl font-bold mb-6 text-center text-green-700">
        Post New Internship
      </h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <input
          type="text"
          name="title"
          placeholder="Internship Title"
          onChange={handleChange}
          className="w-full p-3 border border-gray-300 rounded"
          required
        />
        <input
          type="text"
          name="company"
          placeholder="Company Name"
          onChange={handleChange}
          className="w-full p-3 border border-gray-300 rounded"
          required
        />
        <input
          type="text"
          name="location"
          placeholder="Location"
          onChange={handleChange}
          className="w-full p-3 border border-gray-300 rounded"
          required
        />
        <input
          type="text"
          name="duration"
          placeholder="Duration (e.g., 2 months)"
          onChange={handleChange}
          className="w-full p-3 border border-gray-300 rounded"
        />
        <input
          type="text"
          name="stipend"
          placeholder="Stipend (e.g., ₹5000)"
          onChange={handleChange}
          className="w-full p-3 border border-gray-300 rounded"
        />
        <textarea
          name="description"
          placeholder="Internship Description"
          onChange={handleChange}
          className="w-full p-3 border border-gray-300 rounded h-32"
        ></textarea>

        <button
          type="submit"
          className="bg-green-600 hover:bg-green-700 text-white font-semibold px-6 py-3 rounded w-full"
        >
          Post Internship
        </button>
      </form>
    </div>
  );
}
